namespace sv_d12e91286b834e7094ddecb75c11a0fc.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service (one per circuit) that holds the currently selected warehouse
/// and notifies all subscribers when it changes.
/// </summary>
public class WarehouseStateService
{
    private static readonly List<WarehouseInfo> _warehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A — Downtown" },
        new() { Id = "WH-002", Name = "Warehouse B — Airport" },
        new() { Id = "WH-003", Name = "Warehouse C — Harbor" },
    ];

    public IReadOnlyList<WarehouseInfo> AvailableWarehouses => _warehouses;

    public WarehouseInfo CurrentWarehouse { get; private set; } = _warehouses[0];

    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        var warehouse = _warehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (warehouse is null || warehouse.Id == CurrentWarehouse.Id)
            return;

        CurrentWarehouse = warehouse;

        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_d12e91286b834e7094ddecb75c11a0fc.Services;

/// <summary>
/// Scoped service (one per circuit) that polls for low-stock alerts and
/// notifies all subscribed components when new data arrives.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }

    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChangedAsync;
    }

    /// <summary>Simulates a database query — returns a random number 0–15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Called by components that want polling to be active.
    /// Polling starts on the first subscriber and stops when the last unsubscribes.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
            BeginPollingLoop();
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
            CancelPollingLoop();
    }

    private void BeginPollingLoop()
    {
        CancelPollingLoop();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void CancelPollingLoop()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every 10 seconds.
        await RefreshAlertCountAsync();

        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                await RefreshAlertCountAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on cancellation.
        }
    }

    private async Task RefreshAlertCountAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouse.Id);

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private async Task HandleWarehouseChangedAsync()
    {
        if (_subscriberCount > 0)
            await RefreshAlertCountAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChangedAsync;
        CancelPollingLoop();
    }
}

