@using sv_d12e91286b834e7094ddecb75c11a0fc.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector px-3 py-2">
    <label class="form-label text-light mb-1" style="font-size: 0.75rem;">Current Warehouse</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouse.Id"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChanged;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
            await WarehouseState.SetWarehouseAsync(id);
    }

    private async Task HandleStateChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChanged;
    }
}

